import { Avatar, Button } from 'antd';

const UserList = ['U', 'Lucy', 'Tom', 'Edward'];
const colorList = ['#f56a00', '#7265e6', '#ffbf00', '#00a2ae'];

class Autoset extends React.Component {
  constructor(props) {
    super(props);
    this.state = {
      user: UserList[0],
      color: colorList[0],
    };
  }

  changeUser = () => {
    const index = UserList.indexOf(this.state.user);
    this.setState({
      user: index < UserList.length - 1 ? UserList[index + 1] : UserList[0],
      color: index < colorList.length - 1 ? colorList[index + 1] : colorList[0],
    });
  };

  render() {
    return (
      <div>
        <Avatar style={{ backgroundColor: this.state.color, verticalAlign: 'middle' }} size="large">
          {this.state.user}
        </Avatar>
        <Button
          size="small"
          style={{ marginLeft: 16, verticalAlign: 'middle' }}
          onClick={this.changeUser}
        >
          Change
        </Button>
      </div>
    );
  }
}

ReactDOM.render(<Autoset />, mountNode);

import { Avatar, Button } from 'antd';

class App extends React.Component {
  state = {
    hide: true,
    size: 'large',
    scale: 1,
  };

  toggle = () => {
    this.setState({
      hide: !this.state.hide,
    });
  };

  toggleSize = () => {
    const sizes = ['small', 'default', 'large'];
    let current = sizes.indexOf(this.state.size) + 1;
    if (current > 2) {
      current = 0;
    }
    this.setState({
      size: sizes[current],
    });
  };

  changeScale = () => {
    this.setState({
      scale: this.state.scale === 1 ? 2 : 1,
    });
  };

  render() {
    const { hide, size, scale } = this.state;
    return (
      <div>
        <Button onClick={this.toggle}>Toggle Avatar visibility</Button>
        <Button onClick={this.toggleSize}>Toggle Avatar size</Button>
        <Button onClick={this.changeScale}>Change Avatar scale</Button>
        <br />
        <br />
        <div style={{ textAlign: 'center', transform: `scale(${scale})`, marginTop: 24 }}>
          <Avatar size={size} style={{ background: '#7265e6', display: hide ? 'none' : '' }}>
            Avatar
          </Avatar>
          <Avatar
            size={size}
            src="invalid"
            style={{ background: '#00a2ae', display: hide ? 'none' : '' }}
          >
            Invalid
          </Avatar>
          <div style={{ display: hide ? 'none' : '' }}>
            <Avatar size={size} style={{ background: '#7265e6' }}>
              Avatar
            </Avatar>
            <Avatar size={size} src="invalid" style={{ background: '#00a2ae' }}>
              Invalid
            </Avatar>
          </div>
        </div>
      </div>
    );
  }
}

ReactDOM.render(<App />, mountNode);

